import java.util.Scanner;

public class SecureBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Dynamically allocate memory for buffer based on user input length
        byte[] buffer = new byte[input.length()];

        // Perform bounds checking to prevent buffer overflow
        int copyLength = Math.min(input.length(), buffer.length);

        // Copy user input into the buffer
        System.arraycopy(input.getBytes(), 0, buffer, 0, copyLength);

        // Printing the contents of the buffer
        System.out.println("Buffer contents: " + new String(buffer));
    }
}

